CREATE INDEX IF NOT EXISTS idx_loyalty_rewards_tenant ON loyalty_rewards(tenant_slug);

-- ─── Google Reviews ─────────────────────────
CREATE TABLE IF NOT EXISTS google_reviews (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_slug VARCHAR(100) NOT NULL,
  reviewer_name VARCHAR(200),
  rating INTEGER NOT NULL CHECK (rating BETWEEN 1 AND 5),
  comment TEXT,
  review_date TIMESTAMPTZ,
  sentiment VARCHAR(20),
  responded BOOLEAN DEFAULT FALSE,
  response_text TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_reviews_tenant ON google_reviews(tenant_slug);
CREATE INDEX IF NOT EXISTS idx_reviews_rating ON google_reviews(rating);

-- ─── Marketing Campaign Recipients ──────────
CREATE TABLE IF NOT EXISTS campaign_recipients (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  campaign_id UUID NOT NULL REFERENCES marketing_campaigns(id) ON DELETE CASCADE,
  cliente_id UUID NOT NULL,
  telefono VARCHAR(50),
